160: // Appender returns a new Appender on the database.
161: func (h *Head) Appender(context.Context) storage.Appender {
162: 	h.metrics.activeAppenders.Inc()
163: 
164: 	// The head cache might not have a starting point yet. The init appender
165: 	// picks up the first appended timestamp as the base.
166: 	if !h.initialized() {
167: 		return &initAppender{
168: 			head: h,
169: 		}
170: 	}
171: 	return h.appender()
172: }
