174: func (h *Head) appender() *headAppender {
175: 	minValidTime := h.appendableMinValidTime()
176: 	appendID, cleanupAppendIDsBelow := h.iso.newAppendID(minValidTime) // Every appender gets an ID that is cleared upon commit/rollback.
177: 	return &headAppender{
178: 		headAppenderBase: headAppenderBase{
179: 			head:                  h,
180: 			minValidTime:          minValidTime,
181: 			headMaxt:              h.MaxTime(),
182: 			oooTimeWindow:         h.opts.OutOfOrderTimeWindow.Load(),
183: 			seriesRefs:            h.getRefSeriesBuffer(),
184: 			series:                h.getSeriesBuffer(),
185: 			typesInBatch:          h.getTypeMap(),
186: 			appendID:              appendID,
187: 			cleanupAppendIDsBelow: cleanupAppendIDsBelow,
188: 		},
189: 	}
190: }
191: 
192: // appendableMinValidTime returns the minimum valid timestamp for appends,
193: // such that samples stay ahead of prior blocks and the head compaction window.
194: func (h *Head) appendableMinValidTime() int64 {
195: 	// This boundary ensures that no samples will be added to the compaction window.
196: 	// This allows race-free, concurrent appending and compaction.
197: 	cwEnd := h.MaxTime() - h.chunkRange.Load()/2
198: 
199: 	// This boundary ensures that we avoid overlapping timeframes from one block to the next.
200: 	// While not necessary for correctness, it means we're not required to use vertical compaction.
201: 	minValid := h.minValidTime.Load()
202: 
203: 	return max(cwEnd, minValid)
204: }
205: 
206: // AppendableMinValidTime returns the minimum valid time for samples to be appended to the Head.
207: // Returns false if Head hasn't been initialized yet and the minimum time isn't known yet.
208: func (h *Head) AppendableMinValidTime() (int64, bool) {
209: 	if !h.initialized() {
210: 		return 0, false
211: 	}
212: 
213: 	return h.appendableMinValidTime(), true
214: }
