2001: func newStripeSeries(stripeSize int, seriesCallback SeriesLifecycleCallback) *stripeSeries {
2002: 	s := &stripeSeries{
2003: 		size:                    stripeSize,
2004: 		series:                  make([]map[chunks.HeadSeriesRef]*memSeries, stripeSize),
2005: 		hashes:                  make([]seriesHashmap, stripeSize),
2006: 		locks:                   make([]stripeLock, stripeSize),
2007: 		seriesLifecycleCallback: seriesCallback,
2008: 	}
2009: 
2010: 	for i := range s.series {
2011: 		s.series[i] = map[chunks.HeadSeriesRef]*memSeries{}
2012: 	}
2013: 	for i := range s.hashes {
2014: 		s.hashes[i] = seriesHashmap{
2015: 			unique:    map[uint64]*memSeries{},
2016: 			conflicts: nil, // Initialized on demand in set().
2017: 		}
2018: 	}
2019: 	return s
2020: }
2021: 
2022: // gc garbage collects old chunks that are strictly before mint and removes
2023: // series entirely that have no chunks left.
2024: // note: returning map[chunks.HeadSeriesRef]struct{} would be more accurate,
2025: // but the returned map goes into postings.Delete() which expects a map[storage.SeriesRef]struct
2026: // and there's no easy way to cast maps.
2027: // minMmapFile is the min mmap file number seen in the series (in-order and out-of-order) after gc'ing the series.
2028: func (s *stripeSeries) gc(mint int64, minOOOMmapRef chunks.ChunkDiskMapperRef) (_ map[storage.SeriesRef]struct{}, _ map[labels.Label]struct{}, _, _ int, _, _ int64, minMmapFile int) {
2029: 	var (
2030: 		deleted                  = map[storage.SeriesRef]struct{}{}
2031: 		affected                 = map[labels.Label]struct{}{}
2032: 		rmChunks                 = 0
2033: 		staleSeriesDeleted       = 0
2034: 		actualMint         int64 = math.MaxInt64
2035: 		minOOOTime         int64 = math.MaxInt64
2036: 	)
2037: 	minMmapFile = math.MaxInt32
2038: 
2039: 	// For one series, truncate old chunks and check if any chunks left. If not, mark as deleted and collect the ID.
2040: 	check := func(hashShard int, hash uint64, series *memSeries, deletedForCallback map[chunks.HeadSeriesRef]labels.Labels) {
2041: 		series.Lock()
2042: 		defer series.Unlock()
2043: 
2044: 		rmChunks += series.truncateChunksBefore(mint, minOOOMmapRef)
2045: 
2046: 		if len(series.mmappedChunks) > 0 {
2047: 			seq, _ := series.mmappedChunks[0].ref.Unpack()
2048: 			if seq < minMmapFile {
2049: 				minMmapFile = seq
2050: 			}
2051: 		}
2052: 		if series.ooo != nil && len(series.ooo.oooMmappedChunks) > 0 {
2053: 			seq, _ := series.ooo.oooMmappedChunks[0].ref.Unpack()
2054: 			if seq < minMmapFile {
2055: 				minMmapFile = seq
2056: 			}
2057: 			for _, ch := range series.ooo.oooMmappedChunks {
2058: 				if ch.minTime < minOOOTime {
2059: 					minOOOTime = ch.minTime
2060: 				}
2061: 			}
2062: 		}
2063: 		if series.ooo != nil && series.ooo.oooHeadChunk != nil {
2064: 			if series.ooo.oooHeadChunk.minTime < minOOOTime {
2065: 				minOOOTime = series.ooo.oooHeadChunk.minTime
2066: 			}
2067: 		}
2068: 		if len(series.mmappedChunks) > 0 || series.headChunks != nil || series.pendingCommit ||
2069: 			(series.ooo != nil && (len(series.ooo.oooMmappedChunks) > 0 || series.ooo.oooHeadChunk != nil)) {
2070: 			seriesMint := series.minTime()
2071: 			if seriesMint < actualMint {
2072: 				actualMint = seriesMint
2073: 			}
2074: 			return
2075: 		}
2076: 		// The series is gone entirely. We need to keep the series lock
2077: 		// and make sure we have acquired the stripe locks for hash and ID of the
2078: 		// series alike.
2079: 		// If we don't hold them all, there's a very small chance that a series receives
2080: 		// samples again while we are half-way into deleting it.
2081: 		refShard := int(series.ref) & (s.size - 1)
2082: 		if hashShard != refShard {
2083: 			s.locks[refShard].Lock()
2084: 			defer s.locks[refShard].Unlock()
2085: 		}
2086: 
2087: 		if value.IsStaleNaN(series.lastValue) ||
2088: 			(series.lastHistogramValue != nil && value.IsStaleNaN(series.lastHistogramValue.Sum)) ||
2089: 			(series.lastFloatHistogramValue != nil && value.IsStaleNaN(series.lastFloatHistogramValue.Sum)) {
2090: 			staleSeriesDeleted++
2091: 		}
2092: 
2093: 		deleted[storage.SeriesRef(series.ref)] = struct{}{}
2094: 		series.lset.Range(func(l labels.Label) { affected[l] = struct{}{} })
2095: 		s.hashes[hashShard].del(hash, series.ref)
2096: 		delete(s.series[refShard], series.ref)
2097: 		deletedForCallback[series.ref] = series.lset // OK to access lset; series is locked at the top of this function.
2098: 	}
2099: 
2100: 	s.iterForDeletion(check)
2101: 
2102: 	if actualMint == math.MaxInt64 {
2103: 		actualMint = mint
2104: 	}
2105: 
2106: 	return deleted, affected, rmChunks, staleSeriesDeleted, actualMint, minOOOTime, minMmapFile
2107: }
