2109: // gcStaleSeries removes all the provided series as long as they are still stale
2110: // and the series maxt is <= the given max.
2111: // The returned references are the series that got deleted.
2112: func (h *Head) gcStaleSeries(seriesRefs []storage.SeriesRef, maxt int64) map[storage.SeriesRef]struct{} {
2113: 	// Drop old chunks and remember series IDs and hashes if they can be
2114: 	// deleted entirely.
2115: 	deleted, affected, chunksRemoved := h.series.gcStaleSeries(seriesRefs, maxt)
2116: 	seriesRemoved := len(deleted)
2117: 
2118: 	h.metrics.seriesRemoved.Add(float64(seriesRemoved))
2119: 	h.metrics.chunksRemoved.Add(float64(chunksRemoved))
2120: 	h.metrics.chunks.Sub(float64(chunksRemoved))
2121: 	h.numSeries.Sub(uint64(seriesRemoved))
2122: 	h.numStaleSeries.Sub(uint64(seriesRemoved))
2123: 
2124: 	// Remove deleted series IDs from the postings lists.
2125: 	h.postings.Delete(deleted, affected)
2126: 
2127: 	// Remove tombstones referring to the deleted series.
2128: 	h.tombstones.DeleteTombstones(deleted)
2129: 
2130: 	if h.wal != nil {
2131: 		_, last, _ := wlog.Segments(h.wal.Dir())
2132: 		h.walExpiriesMtx.Lock()
2133: 		// Keep series records until we're past segment 'last'
2134: 		// because the WAL will still have samples records with
2135: 		// this ref ID. If we didn't keep these series records then
2136: 		// on start up when we replay the WAL, or any other code
2137: 		// that reads the WAL, wouldn't be able to use those
2138: 		// samples since we would have no labels for that ref ID.
2139: 		for ref := range deleted {
2140: 			h.walExpiries[chunks.HeadSeriesRef(ref)] = int64(last)
2141: 		}
2142: 		h.walExpiriesMtx.Unlock()
2143: 	}
2144: 
2145: 	return deleted
2146: }
