2148: // deleteSeriesByID deletes the series with the given reference.
2149: // Only used for WAL replay.
2150: func (h *Head) deleteSeriesByID(refs []chunks.HeadSeriesRef) {
2151: 	var (
2152: 		deleted            = map[storage.SeriesRef]struct{}{}
2153: 		affected           = map[labels.Label]struct{}{}
2154: 		staleSeriesDeleted = 0
2155: 		chunksRemoved      = 0
2156: 	)
2157: 
2158: 	for _, ref := range refs {
2159: 		// Delete the reference from the series map.
2160: 		// Copying getByID here to avoid locking and unlocking twice.
2161: 		refShard := int(ref) & (h.series.size - 1)
2162: 		h.series.locks[refShard].Lock()
2163: 		series := h.series.series[refShard][ref]
2164: 		if series == nil {
2165: 			h.series.locks[refShard].Unlock()
2166: 			continue
2167: 		}
2168: 		delete(h.series.series[refShard], series.ref)
2169: 		h.series.locks[refShard].Unlock()
2170: 
2171: 		// Delete the reference from the hash.
2172: 		hash := series.lset.Hash()
2173: 		hashShard := int(hash) & (h.series.size - 1)
2174: 		h.series.locks[hashShard].Lock()
2175: 		h.series.hashes[hashShard].del(hash, series.ref)
2176: 		h.series.locks[hashShard].Unlock()
2177: 
2178: 		if value.IsStaleNaN(series.lastValue) ||
2179: 			(series.lastHistogramValue != nil && value.IsStaleNaN(series.lastHistogramValue.Sum)) ||
2180: 			(series.lastFloatHistogramValue != nil && value.IsStaleNaN(series.lastFloatHistogramValue.Sum)) {
2181: 			staleSeriesDeleted++
2182: 		}
2183: 
2184: 		chunksRemoved += len(series.mmappedChunks)
2185: 		if series.headChunks != nil {
2186: 			chunksRemoved += series.headChunks.len()
2187: 		}
2188: 
2189: 		deleted[storage.SeriesRef(series.ref)] = struct{}{}
2190: 		series.lset.Range(func(l labels.Label) { affected[l] = struct{}{} })
2191: 	}
2192: 
2193: 	h.metrics.seriesRemoved.Add(float64(len(deleted)))
2194: 	h.metrics.chunksRemoved.Add(float64(chunksRemoved))
2195: 	h.metrics.chunks.Sub(float64(chunksRemoved))
2196: 	h.numSeries.Sub(uint64(len(deleted)))
2197: 	h.numStaleSeries.Sub(uint64(staleSeriesDeleted))
2198: 
2199: 	// Remove deleted series IDs from the postings lists.
2200: 	h.postings.Delete(deleted, affected)
