{"content":"639: // appendable checks whether the given sample is valid for appending to the series.
640: // If the sample is valid and in-order, it returns false with no error.
641: // If the sample belongs to the out-of-order chunk, it returns true with no error.
642: // If the sample cannot be handled, it returns an error.
643: func (s *memSeries) appendable(t int64, v float64, headMaxt, minValidTime, oooTimeWindow int64) (isOOO bool, oooDelta int64, err error) {
644: 	// Check if we can append in the in-order chunk.
645: 	if t >= minValidTime {
646: 		if s.headChunks == nil {
647: 			// The series has no sample and was freshly created.
648: 			return false, 0, nil
649: 		}
650: 		msMaxt := s.maxTime()
651: 		if t > msMaxt {
652: 			return false, 0, nil
653: 		}
654: 		if t == msMaxt {
655: 			// We are allowing exact duplicates as we can encounter them in valid cases
656: 			// like federation and erroring out at that time would be extremely noisy.
657: 			// This only checks against the latest in-order sample.
658: 			// The OOO headchunk has its own method to detect these duplicates.
659: 			if s.lastHistogramValue != nil || s.lastFloatHistogramValue != nil {
660: 				return false, 0, storage.NewDuplicateHistogramToFloatErr(t, v)
661: 			}
662: 			if math.Float64bits(s.lastValue) != math.Float64bits(v) {
663: 				return false, 0, storage.NewDuplicateFloatErr(t, s.lastValue, v)
664: 			}
665: 			// Sample is identical (ts + value) with most current (highest ts) sample in sampleBuf.
666: 			return false, 0, nil
667: 		}
668: 	}
669: 
670: 	// The sample cannot go in the in-order chunk. Check if it can go in the out-of-order chunk.
671: 	if oooTimeWindow > 0 && t >= headMaxt-oooTimeWindow {
672: 		return true, headMaxt - t, nil
673: 	}
674: 
675: 	// The sample cannot go in both in-order and out-of-order chunk.
676: 	if oooTimeWindow > 0 {
677: 		return true, headMaxt - t, storage.ErrTooOldSample
678: 	}
679: 	if t < minValidTime {
680: 		return false, headMaxt - t, storage.ErrOutOfBounds
681: 	}
682: 	return false, headMaxt - t, storage.ErrOutOfOrderSample
683: }
