685: // appendableHistogram checks whether the given histogram sample is valid for appending to the series. (if we return false and no error)
686: // The sample belongs to the out of order chunk if we return true and no error.
687: // An error signifies the sample cannot be handled.
688: func (s *memSeries) appendableHistogram(t int64, h *histogram.Histogram, headMaxt, minValidTime, oooTimeWindow int64) (isOOO bool, oooDelta int64, err error) {
689: 	// Check if we can append in the in-order chunk.
690: 	if t >= minValidTime {
691: 		if s.headChunks == nil {
692: 			// The series has no sample and was freshly created.
693: 			return false, 0, nil
694: 		}
695: 		msMaxt := s.maxTime()
696: 		if t > msMaxt {
697: 			return false, 0, nil
698: 		}
699: 		if t == msMaxt {
700: 			// We are allowing exact duplicates as we can encounter them in valid cases
701: 			// like federation and erroring out at that time would be extremely noisy.
702: 			// This only checks against the latest in-order sample.
703: 			// The OOO headchunk has its own method to detect these duplicates.
704: 			if !h.Equals(s.lastHistogramValue) {
705: 				return false, 0, storage.ErrDuplicateSampleForTimestamp
706: 			}
707: 			// Sample is identical (ts + value) with most current (highest ts) sample in sampleBuf.
708: 			return false, 0, nil
709: 		}
710: 	}
