712: 	// The sample cannot go in the in-order chunk. Check if it can go in the out-of-order chunk.
713: 	if oooTimeWindow > 0 && t >= headMaxt-oooTimeWindow {
714: 		return true, headMaxt - t, nil
715: 	}
716: 
717: 	// The sample cannot go in both in-order and out-of-order chunk.
718: 	if oooTimeWindow > 0 {
719: 		return true, headMaxt - t, storage.ErrTooOldSample
720: 	}
721: 	if t < minValidTime {
722: 		return false, headMaxt - t, storage.ErrOutOfBounds
723: 	}
724: 	return false, headMaxt - t, storage.ErrOutOfOrderSample
725: }
