760: 	if oooTimeWindow > 0 {
761: 		return true, headMaxt - t, storage.ErrTooOldSample
762: 	}
763: 	if t < minValidTime {
764: 		return false, headMaxt - t, storage.ErrOutOfBounds
765: 	}
766: 	return false, headMaxt - t, storage.ErrOutOfOrderSample
