769: // AppendExemplar for headAppender assumes the series ref already exists, and so it doesn't
770: // use getOrCreate or make any of the lset validity checks that Append does.
771: func (a *headAppender) AppendExemplar(ref storage.SeriesRef, lset labels.Labels, e exemplar.Exemplar) (storage.SeriesRef, error) {
772: 	// Check if exemplar storage is enabled.
773: 	if !a.head.opts.EnableExemplarStorage || a.head.opts.MaxExemplars.Load() <= 0 {
774: 		return 0, nil
775: 	}
776: 
777: 	// Get Series
778: 	s := a.head.series.getByID(chunks.HeadSeriesRef(ref))
779: 	if s == nil {
780: 		s = a.head.series.getByHash(lset.Hash(), lset)
781: 		if s != nil {
782: 			ref = storage.SeriesRef(s.ref)
783: 		}
784: 	}
785: 	if s == nil {
786: 		return 0, fmt.Errorf("unknown HeadSeriesRef when trying to add exemplar: %d", ref)
787: 	}
788: 
789: 	// Ensure no empty labels have gotten through.
790: 	e.Labels = e.Labels.WithoutEmpty()
791: 
792: 	err := a.head.exemplars.ValidateExemplar(s.labels(), e)
793: 	if err != nil {
794: 		if errors.Is(err, storage.ErrDuplicateExemplar) || errors.Is(err, storage.ErrExemplarsDisabled) {
795: 			// Duplicate, don't return an error but don't accept the exemplar.
796: 			return 0, nil
797: 		}
798: 		return 0, err
799: 	}
