244: // NewHead opens the head block in dir.
245: func NewHead(r prometheus.Registerer, l *slog.Logger, wal, wbl *wlog.WL, opts *HeadOptions, stats *HeadStats) (*Head, error) {
246: 	var err error
247: 	if l == nil {
248: 		l = promslog.NewNopLogger()
249: 	}
250: 
251: 	if opts.OutOfOrderTimeWindow.Load() < 0 {
252: 		opts.OutOfOrderTimeWindow.Store(0)
253: 	}
254: 
255: 	// Time window can be set on runtime. So the capMin and capMax should be valid
256: 	// even if ooo is not enabled yet.
257: 	capMax := opts.OutOfOrderCapMax.Load()
258: 	if capMax <= 0 || capMax > 255 {
259: 		return nil, fmt.Errorf("OOOCapMax of %d is invalid. must be > 0 and <= 255", capMax)
260: 	}
261: 
262: 	if opts.ChunkRange < 1 {
263: 		return nil, fmt.Errorf("invalid chunk range %d", opts.ChunkRange)
264: 	}
265: 	if opts.SeriesCallback == nil {
266: 		opts.SeriesCallback = &noopSeriesLifecycleCallback{}
267: 	}
268: 
269: 	if stats == nil {
270: 		stats = NewHeadStats()
271: 	}
272: 
273: 	if !opts.EnableExemplarStorage {
274: 		opts.MaxExemplars.Store(0)
275: 	}
276: 
277: 	h := &Head{
278: 		wal:    wal,
279: 		wbl:    wbl,
280: 		logger: l,
281: 		opts:   opts,
282: 		memChunkPool: sync.Pool{
283: 			New: func() any {
284: 				return &memChunk{}
285: 			},
286: 		},
287: 		stats: stats,
288: 		reg:   r,
289: 	}
290: 	if err := h.resetInMemoryState(); err != nil {
291: 		return nil, err
292: 	}
293: 
294: 	if opts.ChunkPool == nil {
295: 		opts.ChunkPool = chunkenc.NewPool()
296: 	}
297: 
298: 	if opts.WALReplayConcurrency <= 0 {
299: 		opts.WALReplayConcurrency = defaultWALReplayConcurrency
300: 	}
301: 
302: 	h.chunkDiskMapper, err = chunks.NewChunkDiskMapper(
303: 		r,
304: 		mmappedChunksDir(opts.ChunkDirRoot),
305: 		opts.ChunkPool,
306: 		opts.ChunkWriteBufferSize,
307: 		opts.ChunkWriteQueueSize,
308: 	)
309: 	if err != nil {
310: 		return nil, err
311: 	}
312: 	h.metrics = newHeadMetrics(h, r)
313: 
314: 	return h, nil
315: }
