39: func (a *initAppenderV2) Append(ref storage.SeriesRef, ls labels.Labels, st, t int64, v float64, h *histogram.Histogram, fh *histogram.FloatHistogram, opts storage.AOptions) (storage.SeriesRef, error) {
40: 	if a.app == nil {
41: 		a.head.initTime(t)
42: 		a.app = a.head.appenderV2()
43: 	}
44: 	return a.app.Append(ref, ls, st, t, v, h, fh, opts)
45: }
