70: // AppenderV2 returns a new AppenderV2 on the database.
71: func (h *Head) AppenderV2(context.Context) storage.AppenderV2 {
72: 	h.metrics.activeAppenders.Inc()
73: 
74: 	// The head cache might not have a starting point yet. The init appender
75: 	// picks up the first appended timestamp as the base.
76: 	if !h.initialized() {
77: 		return &initAppenderV2{
78: 			head: h,
79: 		}
80: 	}
81: 	return h.appenderV2()
82: }
