84: func (h *Head) appenderV2() *headAppenderV2 {
85: 	minValidTime := h.appendableMinValidTime()
86: 	appendID, cleanupAppendIDsBelow := h.iso.newAppendID(minValidTime) // Every appender gets an ID that is cleared upon commit/rollback.
87: 	return &headAppenderV2{
88: 		headAppenderBase: headAppenderBase{
89: 			head:                  h,
90: 			minValidTime:          minValidTime,
91: 			headMaxt:              h.MaxTime(),
92: 			oooTimeWindow:         h.opts.OutOfOrderTimeWindow.Load(),
93: 			seriesRefs:            h.getRefSeriesBuffer(),
94: 			series:                h.getSeriesBuffer(),
95: 			typesInBatch:          h.getTypeMap(),
96: 			appendID:              appendID,
97: 			cleanupAppendIDsBelow: cleanupAppendIDsBelow,
98: 		},
99: 	}
100: }
